export function getAgeGroup(age: number | null): string {
  if (age === null || age < 0) return ''
  if (age <= 8)  return '8u'
  if (age <= 10) return '10u'
  if (age <= 12) return '1112'
  if (age <= 14) return '1314'
  if (age <= 16) return '1516'
  if (age <= 18) return '1718'
  return '1718'
}

export function getCut(
  ageGroup: string,
  gender: string,
  course: 'SCY' | 'LCM' | 'SCM',
  eventId: string,
  level: StdLevel,
): string {
  if (!ageGroup || (gender !== 'male' && gender !== 'female')) return ''
  const ag = SCS_STANDARDS[ageGroup]
  if (!ag) return ''
  const gd = ag[gender as 'male' | 'female']
  const cd = gd?.[course]
  return cd?.[eventId]?.[level] ?? ''
}
